// Lite Pack v1.2 · LLM helper（共用骨架，下面業務邏輯維持原樣）
// ════════════════════════════════════════════════════════════
// Lite Pack v1.2 · LLM Helper（共用骨架）
//
// 這段 inject 到每個用 Gemini 的 workflow Code node 開頭。
// 學員客製 workflow 時：
//   - 改 LP_CONFIG → 統一調整 model / timeout / retry / RPM
//   - 用 lpCall(...) 呼叫 LLM → 自動 throttle + retry + 429 處理
//   - 用 lpSizeOK(...) 預檢 inline data → 避免撞 20 MB API limit
//   - 用 lpThrottle() → loop 內呼叫之間 sleep
//
// 換 LLM provider（Gemini → Claude / OpenAI）：只改 lpCall 內的 url/headers/body shape，
// 業務邏輯不動。
// ════════════════════════════════════════════════════════════
const LP = {
  apiKey: $env.GEMINI_API_KEY,
  model: 'gemini-2.5-flash',
  endpoint: 'https://generativelanguage.googleapis.com/v1beta/models',
  rpmDelayMs: 6500,                       // Free tier 10 RPM；paid 改 1000
  maxRetries: 3,
  retry429Ms: 60000,                      // 429 等 60s（quota window）
  retry5xxMs: 5000,                       // 5xx 等 5s
  timeoutMs: 30000,
  maxInlineBytes: 18 * 1024 * 1024,       // 18 MB（保留 buffer to 20 MB hard limit）
};

const lpSleep = ms => new Promise(r => setTimeout(r, ms));

// 主呼叫：自動 retry 429/5xx
// 用法：const r = await lpCall.call(this, { prompt, gen: { maxOutputTokens: 200 } });
//      if (r.ok) use r.text; else use r.error
async function lpCall({ prompt, gen = {}, _att = 0 }) {
  if (!prompt || typeof prompt !== 'string') return { ok: false, text: '', error: 'empty prompt' };
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: LP.endpoint + '/' + LP.model + ':generateContent',
      headers: { 'Content-Type': 'application/json', 'x-goog-api-key': LP.apiKey },
      body: {
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: {
          temperature: 0.4, maxOutputTokens: 400, thinkingConfig: { thinkingBudget: 0 },
          ...gen
        }
      },
      json: true,
      timeout: LP.timeoutMs,
    });
    return {
      ok: true,
      text: r.candidates?.[0]?.content?.parts?.[0]?.text || '',
      finishReason: r.candidates?.[0]?.finishReason || 'unknown',
      attempt: _att,
    };
  } catch (e) {
    const m = (e && e.message) || String(e);
    const r429 = m.includes('429') || m.includes('RESOURCE_EXHAUSTED') || m.includes('quota');
    const r5xx = /\b5\d{2}\b/.test(m) || m.includes('UNAVAILABLE');
    if (_att < LP.maxRetries && (r429 || r5xx)) {
      await lpSleep(r429 ? LP.retry429Ms : LP.retry5xxMs);
      return lpCall.call(this, { prompt, gen, _att: _att + 1 });
    }
    return { ok: false, text: '', error: m.substring(0, 300), attempt: _att };
  }
}

// loop 內 N 筆呼叫之間 sleep（避免撞 RPM）
// 用法：for (let i = 0; i < items.length; i++) { if (i > 0) await lpThrottle(); ... }
async function lpThrottle() { await lpSleep(LP.rpmDelayMs); }

// 預檢 inline data 是否會撞 20 MB API request limit
// 用法：if (!lpSizeOK(binary.data.data)) { /* skip 或 chunk */ }
function lpSizeOK(base64OrBuf) {
  const b = typeof base64OrBuf === 'string'
    ? Math.floor(base64OrBuf.length * 0.75)
    : (base64OrBuf && base64OrBuf.length) || 0;
  return b <= LP.maxInlineBytes;
}

// ════════════════════════════════════════════════════════════
// 業務邏輯（這裡開始是這個 workflow 特有的）
// ════════════════════════════════════════════════════════════
// v0.6：Code node 直接打 Gemini API + 組 Markdown + 組 binary + 組通知文（合併原本三個節點）

const webhookData = $input.first().json;
const question = webhookData.body?.question || webhookData.query?.question || '請告訴我什麼是 n8n？';
const ts = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '').replace(/-/g, '');

const prompt = '請回答以下問題（繁體中文，300 字內，結構化分點）：\n\n' + question;

let raw;
let aiError = null;

const lpResult = await lpCall.call(this, {
  prompt,
  gen: { temperature: 0.6, maxOutputTokens: 800 }
});
if (lpResult.ok) {
  raw = lpResult.text || '（AI 沒回應）';
} else {
  aiError = lpResult.error;
  raw = '（AI 呼叫失敗：' + aiError + '）';
}

const markdown = '# AI 回應 - ' + new Date().toLocaleString('zh-TW') + '\n\n## 問題\n' + question + '\n\n## 回答\n' + raw + '\n';
const outputPath = '/files/shared/ai-output/ai-' + ts + '.md';
// strip Telegram markdown legacy 解析字元，避免 entities error
const stripMD = (s) => String(s).replace(/[*_`\[\]]/g, '');
const tgMsg = '🤖 AI 回應已產生\n\n問：' + stripMD(question.substring(0, 100)) + '\n\n答：' + stripMD(raw.substring(0, 200)) + '...\n\n完整檔：' + outputPath;

return [{
  json: { outputPath, tgMsg, question, answer: raw, aiError },
  binary: {
    data: {
      data: Buffer.from('\ufeff' + (markdown), 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'ai-' + ts + '.md'
    }
  }
}];

// Auto-generated by inject_web_ui.py — 不要直接改這裡的 HTML，改 web-ui/06-ai-ui.html 後重 inject
const html = `<!DOCTYPE html>
<html lang="zh-TW">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>AI 問答 · Lite Pack</title>
<link href="https://fonts.googleapis.com/css2?family=Shippori+Mincho:wght@400;700&family=Noto+Sans+TC:wght@400;500;700&display=swap" rel="stylesheet">
<style>
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  body{font-family:'Noto Sans TC',sans-serif;background:#f5f3ee;color:#2c2b28;line-height:1.7;min-height:100vh;padding:48px 24px}
  .container{max-width:760px;margin:0 auto}
  .eyebrow{font-size:.72rem;color:#b5703a;letter-spacing:1.5px;font-weight:500;margin-bottom:10px}
  h1{font-family:'Shippori Mincho',serif;font-size:1.8rem;font-weight:700;border-bottom:1px solid #d8d4cb;padding-bottom:14px;margin-bottom:14px}
  .sub{color:#7a766d;font-size:.92rem;margin-bottom:32px}
  textarea{width:100%;min-height:110px;padding:14px 16px;border:1px solid #d8d4cb;border-radius:6px;font-size:1rem;font-family:inherit;background:#fff;color:#2c2b28;resize:vertical}
  textarea:focus{outline:none;border-color:#5a7a5a}
  .hint{font-size:.78rem;color:#bcb8ae;margin-top:6px}
  button{padding:11px 32px;background:#5a7a5a;color:white;border:none;border-radius:6px;cursor:pointer;font-size:.95rem;font-weight:500;margin-top:14px;font-family:inherit}
  button:hover{background:#4a6a4a}
  button:disabled{opacity:.5;cursor:not-allowed}
  .result{margin-top:36px;padding:24px;background:#fff;border:1px solid #e8e4da;border-radius:6px;display:none}
  .result.show{display:block}
  .result-q{font-size:.85rem;color:#7a766d;margin-bottom:12px;border-bottom:1px dashed #e8e4da;padding-bottom:10px}
  .result-a{font-size:.95rem;line-height:1.85;white-space:pre-wrap}
  .meta{margin-top:24px;padding-top:16px;border-top:1px solid #e8e4da;font-size:.82rem;color:#7a766d}
  .meta-label{color:#b5703a;font-weight:600;font-size:.75rem;letter-spacing:1px}
  .loading{color:#7a766d;font-style:italic}
  .error{color:#c14a3a;background:#faf0ee;padding:14px;border-radius:6px;border:1px solid #e8d4d0}
  .examples{margin-top:24px;display:flex;gap:8px;flex-wrap:wrap}
  .ex-chip{font-size:.78rem;color:#7a766d;border:1px solid #d8d4cb;background:#fff;padding:5px 12px;border-radius:99px;cursor:pointer;font-family:inherit}
  .ex-chip:hover{color:#5a7a5a;border-color:#5a7a5a}
  .footer{margin-top:48px;padding-top:24px;border-top:1px solid #e8e4da;font-size:.78rem;color:#bcb8ae;text-align:center}
  code{background:#edeae3;padding:2px 6px;border-radius:3px;font-size:.85rem}
</style>
</head>
<body>
<div class="container">
  <div class="eyebrow">LITE PACK · #06</div>
  <h1>🤖 AI 問答</h1>
  <p class="sub">問問題 → AI 生答 → 自動存到 <code>ai-output/</code> 為 .md 檔 + Telegram 通知。適合做「外部觸發 AI + 落地」的範本。</p>

  <textarea id="q" placeholder="輸入你的問題..."></textarea>
  <p class="hint">Ctrl/Cmd + Enter 快速送出</p>

  <div class="examples">
    <button class="ex-chip" onclick="setQ('解釋什麼是 prompt engineering，繁中 200 字內')">解釋 prompt engineering</button>
    <button class="ex-chip" onclick="setQ('幫我寫一封給客戶的延遲交付道歉信')">寫道歉信</button>
    <button class="ex-chip" onclick="setQ('今天有什麼適合 5 分鐘的快速 AI 練習？')">5 分鐘練習</button>
  </div>

  <button id="askBtn" onclick="ask()">問</button>

  <div id="result" class="result"></div>

  <div class="footer">
    <strong>使用前確認</strong>：此 workflow Active = ON（不然 webhook 不接受 production POST）<br>
    POST endpoint：<code>/webhook/ai-ask</code> · GET 此頁面：<code>/webhook/ai-ui</code>
  </div>
</div>

<script>
function setQ(s){document.getElementById('q').value=s;}
function escapeHtml(s){return String(s).replace(/[<>&"']/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;',"'":'&#39;'}[c]))}

async function ask(){
  const q=document.getElementById('q').value.trim();
  if(!q){return;}
  const btn=document.getElementById('askBtn');
  const result=document.getElementById('result');
  btn.disabled=true;btn.textContent='思考中...';
  result.classList.add('show');
  result.innerHTML='<div class="loading">AI 處理中... 答覆會同時寫到 ai-output/ + 推 Telegram</div>';

  try{
    const r=await fetch('/webhook/ai-ask',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({question:q})
    });
    if(!r.ok){throw new Error('HTTP '+r.status+' — 確認 #06 workflow Active = ON');}
    const data=await r.json();

    let html='<div class="result-q"><strong>Q：</strong>'+escapeHtml(data.question||q)+'</div>';
    html+='<div class="result-a">'+escapeHtml(data.answer||data.markdown||'無答覆')+'</div>';
    if(data.outputPath||data.savedTo){
      html+='<div class="meta"><div class="meta-label">已寫入檔案</div>'+escapeHtml(data.outputPath||data.savedTo)+'</div>';
    }
    if(data.telegramSent){
      html+='<div class="meta"><div class="meta-label">Telegram</div>已通知</div>';
    }
    result.innerHTML=html;
  }catch(e){
    result.innerHTML='<div class="error"><strong>錯誤：</strong>'+escapeHtml(e.message)+'</div>';
  }
  btn.disabled=false;btn.textContent='問';
}

document.getElementById('q').addEventListener('keydown',e=>{
  if((e.ctrlKey||e.metaKey)&&e.key==='Enter'){ask();}
});
</script>
</body>
</html>
`;
return [{ json: { html } }];
